final:
module RefModule(
    input  D,
    output Q,
    input  RESET,
    input  SET,
    input  CLK_N
);reg Q_reg;

always @ (negedge CLK_N) begin
    if (RESET) begin
        Q_reg <= 0;
    end else if (SET) begin
        Q_reg <= 1;
    end else begin
        Q_reg <= D;
    end
end

wire __Q_tmp = Q_reg;
assign Q = __Q_tmp;

endmodule
